INSERT INTO `projects` VALUES (6, '💥H.iếm💥Bán Nhà Phú Nhuận – Xe Hơi Ngủ Nhà – Gần Q.uận 1 – Sát Khu Phan Xích Long – 5 Tầng BTCT – 40m2 – 4PN 5WC – Hoàn Công Đủ – Vào Ở Ngay – Chỉ 9.79 tỷ', 'hiemban-nha-phu-nhuan-xe-hoi-ngu-nha-gan-quan-1-sat-khu-phan-xich-long-5-tang-btct-40m2-4pn-5wc-hoan-cong-du-vao-o-ngay-chi-979-ty', '<h4><strong style=\"background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);\">Mô tả</strong></h4><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(118, 118, 118);\">📍 Vị trí : ngay Thích Quảng Đức thông Hoàng Hoa Thám, gần Khu Phan Xích Long, Bà Chiểu và đi Quận 1 chỉ 15′</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(118, 118, 118);\">🏗️ Kết cấu : 1 trệt 1 lững 3 lầu. Gồm 4PN 5WC, phòng khách, bếp, ban công thoáng mát</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(118, 118, 118);\">📐 Diện tích : 3.95m x 10.2m</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(118, 118, 118);\">🚗 Hẻm xe hơi đỗ cửa, khu nhà cao tầng, an ninh sạch sẽ</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(118, 118, 118);\">📖 Sổ hồng riêng, hoàn công đủ, công chứng nhanh</span></p><p><br></p>', '💥H.iếm💥Bán Nhà Phú Nhuận – Xe Hơi Ngủ Nhà – Gần Q.uận 1 – Sát Khu Phan Xích Long – 5 Tầng BTCT – 40m2 – 4PN 5WC – Hoàn Công Đủ – Vào Ở Ngay – Chỉ 9.79 tỷ', '1, Thành phố Hà Giang, Tỉnh Hà Giang', '9.7 tỷ', 402, 0, 0, '/api/uploads/1783002760787-img_7553.jpeg', '/api/uploads/1783002760795-img_7556-225x300.jpeg', NULL, 0, 'listing', '2026-07-02 21:32:40', '[\"/api/uploads/1783002760787-img_7553.jpeg\", \"/api/uploads/1783002760795-img_7556-225x300.jpeg\", \"/api/uploads/1783002760795-img_7555-225x300.jpeg\", \"/api/uploads/1783002760797-img_7554-300x225.jpeg\", \"/api/uploads/1783002760797-img_7553-225x300.jpeg\"]', 'BÁN CĂN HỘ CHUNG CƯ', 3, 'published', '', NULL, NULL, NULL, NULL, NULL, NULL, 1, 1, 1, 1, NULL);
INSERT INTO `projects` VALUES (7, 'Mua nhà 852 – Đường Nơ Trang Long, Bình Lợi Trung, Bình Thạnh, Cách hẻm xe hơi chỉ 1 nhà, 5.3x11m, 3 Tầng, 7.45 Tỷ (TL)', 'mua-nha-852-duong-no-trang-long-binh-loi-trung-binh-thanh-cach-hem-xe-hoi-chi-1-nha-53x11m-3-tang-745-ty-tl', '<h4><strong style=\"background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);\">Mô tả</strong></h4><h2><strong style=\"background-color: rgb(255, 255, 255); color: rgb(39, 174, 96); font-size: calc(24px * var(--text-scale));\" data-orig-font-size=\"24px\">🌿 Tuyệt Tác Nhà Phố – Không Gian Sống Đẳng Cấp &amp; Riêng Tư 🌿</strong></h2><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(44, 62, 80);\">✨ Được thiết kế bởi kiến trúc sư chuyên nghiệp, căn nhà mang đến không gian sống </span><strong style=\"background-color: rgb(255, 255, 255); color: rgb(44, 62, 80);\">thoáng đãng trước – sau</strong><span style=\"background-color: rgb(255, 255, 255); color: rgb(44, 62, 80);\">, tối ưu ánh sáng và gió tự nhiên, tạo cảm giác thư thái mỗi ngày.</span></p><ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"color: rgb(44, 62, 80); background-color: rgb(246, 255, 250);\">🏡 </span><strong style=\"color: rgb(44, 62, 80); background-color: rgb(246, 255, 250);\">Công năng vượt trội:</strong><span style=\"color: rgb(44, 62, 80); background-color: rgb(246, 255, 250);\"> 4 phòng ngủ, 4 WC, phòng trà thư giãn, phòng xông hơi riêng – chuẩn phong cách sống cao cấp.</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"color: rgb(44, 62, 80); background-color: rgb(246, 255, 250);\">🛋️ </span><strong style=\"color: rgb(44, 62, 80); background-color: rgb(246, 255, 250);\">Nội thất:</strong><span style=\"color: rgb(44, 62, 80); background-color: rgb(246, 255, 250);\"> Trang bị full nội thất cao cấp, dọn vào ở ngay.</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"color: rgb(44, 62, 80); background-color: rgb(246, 255, 250);\">🌬️ </span><strong style=\"color: rgb(44, 62, 80); background-color: rgb(246, 255, 250);\">Mặt tiền rộng 5.3m:</strong><span style=\"color: rgb(44, 62, 80); background-color: rgb(246, 255, 250);\"> Không gian cực kỳ thoáng, kết hợp sân thượng trước – sau đón gió và ánh sáng tự nhiên.</span></li></ol><p><span style=\"color: rgb(44, 62, 80); background-color: rgb(255, 249, 230);\">📍 </span><strong style=\"color: rgb(44, 62, 80); background-color: rgb(255, 249, 230);\">Vị trí vàng:</strong><span style=\"color: rgb(44, 62, 80); background-color: rgb(255, 249, 230);\"> Chỉ cách hẻm xe hơi 1 căn, ngay sát mặt tiền Nơ Trang Long – di chuyển thuận tiện nhưng vẫn giữ được sự </span><strong style=\"color: rgb(44, 62, 80); background-color: rgb(255, 249, 230);\">yên tĩnh, riêng tư</strong><span style=\"color: rgb(44, 62, 80); background-color: rgb(255, 249, 230);\">.</span></p><p><br></p><p><span style=\"color: rgb(44, 62, 80); background-color: rgb(255, 249, 230);\">👨‍🎓 Khu dân cư văn minh, dân trí cao – lý tưởng để an cư lâu dài.</span></p><p><span style=\"color: rgb(44, 62, 80); background-color: rgb(253, 236, 234);\">📜 </span><strong style=\"color: rgb(44, 62, 80); background-color: rgb(253, 236, 234);\">Pháp lý chuẩn chỉnh:</strong><span style=\"color: rgb(44, 62, 80); background-color: rgb(253, 236, 234);\"> Sổ hồng cất két – sẵn sàng giao dịch ngay.</span></p><p><strong style=\"background-color: rgb(255, 255, 255); color: rgb(192, 57, 43); font-size: calc(16px * var(--text-scale));\" data-orig-font-size=\"16px\">🔥 Cơ hội sở hữu căn nhà đáng sống bậc nhất khu vực – xem là thích ngay!</strong></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(118, 118, 118);\"><img src=\"https://nhathathcm.com/wp-content/uploads/2026/04/mua-nha-852-1.jpg\" height=\"auto\" style=\"box-sizing: border-box; margin: 0px auto 20px; padding: 0px; border: 0px; vertical-align: middle; font-style: inherit; font-var