INSERT INTO `projects` VALUES (8, 'Mua nhà 846 – Đường Huỳnh Đình Hai, Bình Thạnh, Bình Thạnh, Hẻm xe hơi, 4x13m, 5 Tầng, 11.9 Tỷ (TL)', 'mua-nha-846-duong-huynh-dinh-hai-binh-thanh-binh-thanh-hem-xe-hoi-4x13m-5-tang-119-ty-tl', '<h4><strong style=\"background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);\">Mô tả</strong></h4><h2><strong style=\"background-color: rgb(255, 255, 255); color: rgb(231, 76, 60); font-size: calc(24px * var(--text-scale));\" data-orig-font-size=\"24px\">🔥 NHÀ 5 TẦNG – HẺM XE HƠI – GẦN CHỢ BÀ CHIỂU – CƠ HỘI ĐẦU TƯ HIẾM!</strong></h2><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(44, 62, 80);\">💎 Sở hữu ngay căn nhà vị trí vàng tại Bình Thạnh – vừa ở đẳng cấp, vừa khai thác dòng tiền ổn định mỗi tháng!</span></p><ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"color: rgb(44, 62, 80); background-color: rgb(248, 249, 250);\">📐 </span><strong style=\"color: rgb(44, 62, 80); background-color: rgb(248, 249, 250);\">Diện tích:</strong><span style=\"color: rgb(44, 62, 80); background-color: rgb(248, 249, 250);\"> 52m² (ngang 4m – nở hậu 4.2m)</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"color: rgb(44, 62, 80); background-color: rgb(248, 249, 250);\">🏢 </span><strong style=\"color: rgb(44, 62, 80); background-color: rgb(248, 249, 250);\">Kết cấu:</strong><span style=\"color: rgb(44, 62, 80); background-color: rgb(248, 249, 250);\"> 1 trệt, 1 lửng, 2 lầu, sân thượng – thiết kế tối ưu không gian</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"color: rgb(44, 62, 80); background-color: rgb(248, 249, 250);\">🛏️ </span><strong style=\"color: rgb(44, 62, 80); background-color: rgb(248, 249, 250);\">Công năng:</strong><span style=\"color: rgb(44, 62, 80); background-color: rgb(248, 249, 250);\"> 3 phòng ngủ rộng rãi, 4 WC tiện nghi</span></li></ol><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(44, 62, 80);\">🚗 </span><strong style=\"background-color: rgb(255, 255, 255); color: rgb(44, 62, 80);\">Hẻm xe hơi nội bộ</strong><span style=\"background-color: rgb(255, 255, 255); color: rgb(44, 62, 80);\"> yên tĩnh, an ninh, chỉ vài căn – đậu ô tô trước nhà cực kỳ thoải mái.</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(44, 62, 80);\">📍 </span><strong style=\"background-color: rgb(255, 255, 255); color: rgb(44, 62, 80);\">Vị trí đắc địa:</strong><span style=\"background-color: rgb(255, 255, 255); color: rgb(44, 62, 80);\"> Gần chợ Bà Chiểu, BV Gia Định, Lăng Ông – di chuyển thuận tiện mọi hướng.</span></p><p><span style=\"color: rgb(44, 62, 80); background-color: rgb(255, 243, 205);\">💰 </span><strong style=\"color: rgb(44, 62, 80); background-color: rgb(255, 243, 205);\">Dòng tiền hấp dẫn:</strong><span style=\"color: rgb(44, 62, 80); background-color: rgb(255, 243, 205);\"> Nhà đang cho thuê </span><strong style=\"color: rgb(44, 62, 80); background-color: rgb(255, 243, 205);\">23 triệu/tháng</strong><span style=\"color: rgb(44, 62, 80); background-color: rgb(255, 243, 205);\"> – phù hợp mua giữ tài sản hoặc đầu tư lâu dài.</span></p><p><span style=\"color: rgb(44, 62, 80); background-color: rgb(234, 250, 241);\">📜 </span><strong style=\"color: rgb(44, 62, 80); background-color: rgb(234, 250, 241);\">Pháp lý:</strong><span style=\"color: rgb(44, 62, 80); background-color: rgb(234, 250, 241);\"> Sổ hồng riêng, minh bạch – sang tên nhanh chóng.</span></p><p><span style=\"color: rgb(44, 62, 80); background-color: rgb(253, 236, 234);\">⚡ </span><strong style=\"color: rgb(44, 62, 80); background-color: rgb(253, 236, 234);\">Giá chào:</strong><span style=\"color: rgb(44, 62, 80); background-color: rgb(253, 236, 234);\"> 12.5 tỷ (còn thương lượng cho khách thiện chí)</span></p><p><strong style=\"background-color: rgb(255, 255, 255); color: rgb(192, 57, 43);\">📞 Liên hệ ngay để xem nhà (báo trước 1 tiếng) – đừng bỏ lỡ căn nhà vừa đẹp vừa sinh lời này!</strong></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(118, 118, 118);\"><img src=\"https://nhathathcm.com/wp-content/uploads/2026/04/mua-nha-846-1.jpg\" height=\"auto\" style=\"box-sizing: border-box; margin: 0px auto 20px; padding: 0px; border: 0px; vertical-align: middle; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; font-language-override: inherit; font-size: calc(15px * var(--text-scale)); max-width: 100%; height: auto; clear: both; display: block;\" alt=\"mua nhà Bình Thạnh\" class=\"aligncenter\" data-orig-font-size=\"15px\"></span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(118, 118, 118);\"><img src=\"https://nhathathcm.com/wp-content/uploads/2026/04/mua-nha-846-2.jpg\" height=\"auto\" style=\"box-sizing: border-box; margin: 0px auto 20px; padding: 0px; border: 0px; vertical-align: middle; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; font-language-override: inherit; font-size: calc(15px * var(--text-scale)); max-width: 100%; height: auto; clear: both; display: block;\" alt=\"mua nhà Bình Thạnh\" class=\"aligncenter\" data-orig-font-size=\"15px\"></span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(118, 118, 118);\"><img src=\"https://nhathathcm.com/wp-content/uploads/2026/04/mua-nha-846-3.jpg\" height=\"auto\" style=\"box-sizing: border-box; margin: 0px auto 20px; padding: 0px; border: 0px; vertical-align: middle; font-style: inherit; font-variant: inherit; font-weight: inh