INSERT INTO `projects` VALUES (9, 'Mua nhà 834 – Đường Bạch Đằng, Gia Định, Bình Thạnh, Hẻm trước nhà 3m, 3.6x8m, 3 Tầng, 5.98 Tỷ (TL)', 'mua-nha-834-duong-bach-dang-gia-dinh-binh-thanh-hem-truoc-nha-3m-36x8m-3-tang-598-ty-tl', '<h4><strong style=\"background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);\">Mô tả</strong></h4><h2><strong style=\"background-color: rgb(255, 255, 255); color: rgb(231, 76, 60); font-size: calc(24px * var(--text-scale));\" data-orig-font-size=\"24px\">🔥 Nhà Đẹp Bạch Đằng – Trung Tâm Hàng Xanh, Full Nội Thất, Vào Ở Ngay!</strong></h2><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(44, 62, 80);\">✨ Sở hữu ngay bất động sản tọa lạc tại vị trí “vàng” </span><strong style=\"background-color: rgb(255, 255, 255); color: rgb(44, 62, 80);\">đường Bạch Đằng – Ngã tư Hàng Xanh</strong><span style=\"background-color: rgb(255, 255, 255); color: rgb(44, 62, 80);\">,</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(44, 62, 80);\">nơi hội tụ nhịp sống sôi động bậc nhất Bình Thạnh, kết nối cực nhanh đến mọi khu vực trọng điểm.</span></p><p><span style=\"color: rgb(44, 62, 80); background-color: rgb(248, 249, 250);\">📍 </span><strong style=\"color: rgb(44, 62, 80); background-color: rgb(248, 249, 250);\">Vị trí đắc địa:</strong><span style=\"color: rgb(44, 62, 80); background-color: rgb(248, 249, 250);\"> Bao quanh bởi hàng loạt trường đại học lớn như HUTECH, Ngoại Thương, Hồng Bàng, Tài Chính…</span></p><p><span style=\"color: rgb(44, 62, 80); background-color: rgb(248, 249, 250);\">🚗 Di chuyển cực tiện đến Quận 1, Quận 2, Sân Bay chỉ trong vài phút.</span></p><ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"background-color: rgb(255, 255, 255); color: rgb(44, 62, 80);\">🏘️ </span><strong style=\"background-color: rgb(255, 255, 255); color: rgb(44, 62, 80);\">Hẻm trước nhà:</strong><span style=\"background-color: rgb(255, 255, 255); color: rgb(44, 62, 80);\"> Rộng ~3m, sạch đẹp, khu dân trí cao, an ninh – yên tĩnh. Chỉ vài bước chân ra mặt tiền.</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"background-color: rgb(255, 255, 255); color: rgb(44, 62, 80);\">🏡 </span><strong style=\"background-color: rgb(255, 255, 255); color: rgb(44, 62, 80);\">Kết cấu:</strong><span style=\"background-color: rgb(255, 255, 255); color: rgb(44, 62, 80);\"> 1 trệt, 2 lầu đúc BTCT kiên cố – thiết kế hiện đại, tối ưu không gian.</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"background-color: rgb(255, 255, 255); color: rgb(44, 62, 80);\">🛏️ </span><strong style=\"background-color: rgb(255, 255, 255); color: rgb(44, 62, 80);\">Công năng:</strong><span style=\"background-color: rgb(255, 255, 255); color: rgb(44, 62, 80);\"> 3 phòng ngủ, 3 WC, phòng khách &amp; bếp mở, gara xe, phòng giặt phơi, ban công, giếng trời thoáng sáng.</span></li></ol><p><span style=\"color: rgb(44, 62, 80); background-color: rgb(255, 247, 230);\">🎁 </span><strong style=\"color: rgb(44, 62, 80); background-color: rgb(255, 247, 230);\">Tặng FULL nội thất cao cấp:</strong><span style=\"color: rgb(44, 62, 80); background-color: rgb(255, 247, 230);\"> Sofa, TV, máy lạnh, máy giặt, bàn ăn, tủ bếp, giường, nệm, tủ quần áo, bàn trang điểm…</span></p><p><span style=\"color: rgb(44, 62, 80); background-color: rgb(255, 247, 230);\">👉 Xách vali vào ở ngay!</span></p><ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"background-color: rgb(255, 255, 255); color: rgb(44, 62, 80);\">📐 </span><strong style=\"background-color: rgb(255, 255, 255); color: rgb(44, 62, 80);\">Diện tích:</strong><span style=\"background-color: rgb(255, 255, 255); color: rgb(44, 62, 80);\"> 27m² (3.6m x 8m) – sổ đẹp, nở hậu nhẹ mang tài lộc.</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"background-color: rgb(255, 255, 255); color: rgb(44, 62, 80);\">🌆 </span><strong style=\"background-color: rgb(255, 255, 255); color: rgb(44, 62, 80);\">Khu vực:</strong><span style=\"background-color: rgb(255, 255, 255); color: rgb(44, 62, 80);\"> Dân cư hiện hữu, không vướng quy hoạch hay lộ giới.</span></li></ol><p><span style=\"color: rgb(44, 62, 80); background-color: rgb(253, 242, 242);\">📜 </span><strong style=\"color: rgb(44, 62, 80); background-color: rgb(253, 242, 242);\">Pháp lý chuẩn chỉnh:</strong><span style=\"color: rgb(44, 62, 80); background-color: rgb(253, 242, 242);\"> Hoàn công đầy đủ, sổ hồng riêng, công chứng ngay trong ngày.</span></p><p><strong style=\"background-color: rgb(255, 255, 255); color: rgb(231, 76, 60);\">⚡ Sản phẩm hiếm ngay trung tâm – phù hợp ở ngay hoặc đầu tư khai thác cực tốt!</strong></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(118, 118, 118);\"><img src=\"https://nhathathcm.com/wp-content/uploads/2026/04/mua-nha-834-1.jpg\" height=\"auto\" style=\"box-sizing: border-box; margin: 0px auto 20px; padding: 0px; border: 0px; vertical-align: middle; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; font-language-override: inherit; font-size: calc(15px * var(--text-scale)); max-width: 100%; height: auto; clear: both; display: block;\" alt=\"mua nhà Bình Thạnh\" class=\"aligncenter\" data-orig-font-size=\"15px\"></span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(118, 118, 118);\"><img src=\"https://nhathathcm.com/wp-content/uploads/2026/04/mua-nha-834-2.jpg\" height=\"auto\" style=\"box-sizing: border-box; margin: 0px auto 20px; padding: 0px; border: 0px; vertical-align: middle; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inh