INSERT INTO `projects` VALUES (13, 'Nhanh Mới Kịp💥Bán Nhà Bình Thạnh – Phan Văn Hân – Ngay Thị Nghè – Sát Mặt Tiền – Giáp Quận 1 – Gần Hàng Xanh – Hẻm 4m – 2 Tầng ~ 45m2 – Chỉ 7.5 tỷ', 'nhanh-moi-kipban-nha-binh-thanh-phan-van-han-ngay-thi-nghe-sat-mat-tien-giap-quan-1-gan-hang-xanh-hem-4m-2-tang-45m2-chi-75-ty', '<h4><strong style=\"background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);\">Mô tả</strong></h4><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(118, 118, 118);\">+ Vị trí : Phan Văn Hân thông Trường Sa, ngay thị nghè cách Q1 chỉ cây cầu, gần ĐH : Hồng Bàng, Hutech, Ngoại Thương</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(118, 118, 118);\">+ Kết cấu : 1 trệt 1 lầu. Gồm phòng khách, bếp 3PN (có PN trệt cho người lớn tuổi) 3WC, ban công, sân vườn, giếng trời thoáng mát, trước nhà có sân để xe máy</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(118, 118, 118);\">+ Diện tích : 3m x 14m</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(118, 118, 118);\">+ Hẻm 4m sạch sẽ, an ninh yên tĩnh</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(118, 118, 118);\">+ Sổ hồng riêng, công chứng nhanh</span></p><p><br></p>', '', '222, Thành phố Bắc Ninh, Tỉnh Bắc Ninh', '20.5 Tỷ ', 200, 0, 0, '/api/uploads/1783006038001-img_8640.jpeg', '/api/uploads/1783006037980-img_8650.jpeg', NULL, 1, 'listing', '2026-07-02 22:27:18', '[\"/api/uploads/1783006038001-img_8640.jpeg\", \"/api/uploads/1783006037980-img_8650.jpeg\", \"/api/uploads/1783006037990-img_8643.jpeg\", \"/api/uploads/1783006037995-img_8641-1024x768.jpeg\"]', 'BÁN CĂN HỘ CHUNG CƯ', 1, 'published', '', NULL, NULL, NULL, NULL, NULL, NULL, 1, 1, 1, 1, NULL);
